def validate_title(title: str) -> None:
    if not title or title.strip() == "":
        raise ValueError("Title cannot be empty or only spaces")

def validate_id(task_id: int) -> None:
    if task_id < 0:
        raise ValueError("ID cannot be negative")

def _run_tests():
    try:
        # Valid title
        validate_title("Valid Title")
        # Empty title should raise
        try:
            validate_title("")
            raise AssertionError("Empty title did not raise ValueError")
        except ValueError:
            pass
        # Spaces-only title should raise
        try:
            validate_title("   ")
            raise AssertionError("Spaces-only title did not raise ValueError")
        except ValueError:
            pass
        # Valid IDs (including zero)
        validate_id(5)
        validate_id(0)
        # Negative ID should raise
        try:
            validate_id(-1)
            raise AssertionError("Negative ID did not raise ValueError")
        except ValueError:
            pass
        print("CRITERIO OK")
    except Exception as exc:
        print(f"CRITERIO FALLO: {exc}")

if __name__ == "__main__":
    _run_tests()

from flask import Flask, jsonify

app = Flask(__name__)

@app.route("/", methods=["GET"])
def hello():
    """Simple endpoint that returns a greeting."""
    return jsonify(message="Hello")


if __name__ == "__main__":
    try:
        with app.test_client() as client:
            response = client.get("/")
            # Validate response
            if response.status_code != 200:
                raise AssertionError(f"unexpected status code -> {response.status_code}")
            data = response.get_json()
            if not (isinstance(data, dict) and data.get("message") == "Hello"):
                raise AssertionError(f"unexpected JSON payload -> {data}")
            print("CRITERIO OK")
    except AssertionError as ae:
        print(f"CRITERIO FALLO: {ae}")
    except Exception as exc:  # pragma: no cover
        print(f"CRITERIO FALLO: exception during test -> {exc}")

